require "objects"
require "utils"
require "particles"
require "events"
require "eprint"

heroes_data = {
	{x=120,y=60,c=9,spr=45,px=2,py=218,pspr=12,name="aguaman",strong="fire",weak="gun"},
	{x=10,y=60,c=14,spr=44,px=22,py=218,pspr=14,name="milkachu",strong="gun",weak="unrest"},
	{x=80,y=60,c=7,spr=60,px=42,py=218,pspr=46,name="greyjean",strong="unrest",weak="fire"}
}

-- sfx(id, [note=-1], [duration=-1], [channel=0], [volume=15], [speed=0])

function BOOT()
	t=0
	gstate = 1 -- 1 game -- 2 endscreen
	objects = {}
	heroes = {mcap={c=4,pspr=10},info={c=14,pspr=8}}
	inputs = {x=0,y=0,left=false,clickL=false,releaseL=false}
	selected = nil
	event_idx = 1
	next_threat = 60
	spawn_threats = true
	thp = {xmin=20,xmax=240,ymin=20,ymax=118,dmin=1500,dmax=1500,smin=480,smax=480}
	threats = {"fire","gun","unrest"}
	init_heros(heroes_data)
	-- rain effect
	-- make_rain_ps(20, 0)
	-- make_rain_ps(20, 0)
	-- make_rain_ps(20, 0)
	-- make_rain_ps(20, 0)
	--
	-- threat:spawn(50, 25, 2500, 480, "fire")
	-- threat:spawn(100, 25, 2500, 480, "gun")
	-- threat:spawn(155, 25, 2500, 480, "unrest")
	-- local v = create(villain, 80, 60)
end

function init_heros(heroes_data)
	for index, value in ipairs(heroes_data) do
		local h = create(hero, value.x, value.y)
		h.c, h.spr = value.c, value.spr
		h.pspr = value.pspr
		h.strong = value.strong
		h.weak = value.weak
		heroes[value.name] = h
		local p = create(portrait, value.px, value.py)
		p.hero = h
		p.spr = value.pspr
	end
end

function TIC()
	update()
	draw()
	t=t+1
end

function update()
	if gstate ~= 1 then return end
	updateInputs()
	if inputs.clickR then
		if selected and selected.parent == hero then
			selected:set_target(inputs.x, inputs.y)
			sfx(23,'C-1',-1,3,15,0)
		end
	end
	--
	local clickt = false
	for i, obj in ipairs(objects) do
        if update_obj(obj, i) then
			clickt = true
		end
    end
	if not clickt and inputs.clickL then
		selected = nil
	end
	update_lvl()
	update_psystems()
end

function update_lvl()
	ts = math.floor(t/60)

	-- auto spawn theats
	if ts >= next_threat and spawn_threats then
		local x, y = math.random(thp.xmin,thp.xmax), math.random(thp.ymin,thp.ymax)
		local delay, score = math.random(thp.dmin,thp.dmax), math.random(thp.smin,thp.smax)
		local type = rchoice(threats)
		threat:spawn(x,y,delay,score,type)
		next_threat = ts + math.random(8, 10)
	end

	-- programmed events
	if event_idx > #events then return end

	evt = events[event_idx]
	if ts < evt.t then return end

	if evt.type == "text" then
		current_text = evt.text
		if evt.char then
			current_spr = heroes[evt.char].pspr
			text_color = heroes[evt.char].c
		else
			current_spr = nil
		end
	elseif evt.type == "villain" then
		create(villain, -10, -10)
	elseif evt.type == "stop" then
		spawn_threats = false
	elseif evt.type == "rain" then
		make_rain_ps(20, 0)
	elseif evt.type == "music" then
		-- music([track=-1], [frame=-1], [row=-1], [loop=true], [sustain=false], [tempo=-1], [speed=-1])
		local tempo, speed = evt.tempo or -1, evt.speed or -1
		music(evt.track, -1, -1, true, false, tempo, speed)
	else
		threat:spawn(evt.x, evt.y, evt.delay, evt.score, evt.type)
	end

	event_idx = event_idx + 1
end

function update_obj(obj, i)
	local clickt = false
	obj.hover=obj:contains(inputs.x, inputs.y)
	if (obj.hover and inputs.clickL) then
		obj:on_click()
		clickt = true
	end
	obj:update()
	if obj.destroyed then
		table.remove(objects, i)
	end
	return clickt
end

function updateInputs()
	local x,y,left,middle,right=mouse()
	inputs.x = x
	inputs.y = y
	inputs.clickL = not inputs.left and left
	inputs.releaseL = inputs.left and not left
	inputs.left = left
	inputs.clickR = not inputs.right and right
	inputs.right = right
end

function draw()
	cls(0)
	map()
	--
	draw_psystems()
	--
	for i, obj in ipairs(objects) do
        obj:draw()
    end
	--
	draw_texts()
	if gstate == 2 then
		rect(40,20,160,80,14)
		rectb(40,20,160,80,3)
		eprint("Thank you for playing !", {40,200}, 0, {20,100}, 0, 3, true, 2, false, 0, 2, false, 15)
	end
	--
	print(math.floor(t/60),2, 2, 3)
	print(math.floor(t/60),1, 1, 14)
	print(test,1, 8, 14)
end

ztext = {
	{x={18,120},y={120,136}},
	{x={120,222},y={120,136}},
	{x={18,240},y={122,136}}
}

current_text = nil
text_color = nil
current_spr = nil

function draw_texts()
	rect(0,120,240,20,1)
	rectb(0,120,240,16,2)
	if current_text then
		eprint(current_text,ztext[3].x,-1,ztext[3].y,-1,14,false,1,false,0,0,false,3)
	end
	if current_spr then
		spr(current_spr,1,120,-1,1,0,0,2,2)
		rectb(0,119,17,17,text_color)
	end
end

